def handle(self, **kwargs):
        feed_urls = set(
            Feed.objects.filter(approval_status=APPROVED_FEED).values_list(
                "feed_url", flat=True
            )
        )

        subscribed_urls = set(Subscription.objects.values_list("topic", flat=True))

        missing_feeds = feed_urls - subscribed_urls
        extra_feeds = subscribed_urls - feed_urls

        for url in missing_feeds:
            logger.info(f"Subscribing to {url}")
            Subscription.objects.subscribe(url, settings.PUSH_HUB)

        for subscription in Subscription.objects.filter(topic__in=extra_feeds):
            logger.info(f"Unsubscribing from {subscription.pk} ({subscription.topic})")
            subscription.unsubscribe()

        limit = timezone.now() + timedelta(days=2)
        for subscription in Subscription.objects.exclude(topic__in=extra_feeds).filter(
            lease_expiration__lte=limit
        ):
            logger.info(
                f"Renewing subscription for {subscription.topic} ({subscription.pk})"
            )
            subscription.subscribe()

def dummy_upload(request):
    if getattr(settings, 'ENV', None) == 'prod':
        raise PermissionDenied
    # dd if=/dev/urandom of=/tmp/test.img bs=100M count=1
    # curl -F parse=1 -F upload=@/tmp/test.img <host>/services/dummy_upload
    if request.POST.get('parse') and 'upload' in request.FILES:
        buf = request.FILES['upload'].read()
    else:
        buf = ''
    # Additional delay to test timeout behavior.
    if 'delay' in request.POST:
        try:
            delay = int(request.POST.get('delay', 1))
            if delay > 120 or delay < 0:
                raise ValueError
        except ValueError:
            delay = 1
        time.sleep(delay)
    else:
        delay = None

    return JsonResponse(
        {
            # request._start_time is set by GraphiteRequestTimingMiddleware
            'elapsed_in_app': int((time.time() - request._start_time) * 1000),
            'buf_size': len(buf),
            'delay': delay,
        }
    )

def resolve_filter(self, info, **kwargs):
        field = getattr(self, field_name)

        if not filterset_class or not kwargs:
            return field.all()

        # Backwards-compatibility with Nautobot v2 - "_type" as a (now deprecated) alias for "type" filter
        if "_type" in kwargs:
            _type = kwargs.pop("_type")
            if "type" not in kwargs:
                kwargs["type"] = _type

        if not hasattr(info.context, "_gql_filter_cache"):
            info.context._gql_filter_cache = {}

        related_model = field.model
        cache_key = (related_model._meta.label, field_name, _make_filter_cache_key(kwargs))

        if cache_key not in info.context._gql_filter_cache:
            resolved_obj = filterset_class(kwargs, related_model.objects.all())

            if resolved_obj.errors:
                raise GraphQLError(str(dict(resolved_obj.errors)))

            # Cache the filterset evaluation per request to avoid N+1 queries.
            info.context._gql_filter_cache[cache_key] = set(resolved_obj.qs.values_list("pk", flat=True))

        matching_ids = info.context._gql_filter_cache[cache_key]
        return [obj for obj in field.all() if obj.pk in matching_ids]

def get_or_create_at_sizes(self, image, sizes):
        sizes_to_create = list(sizes)
        sized = {}
        for size in sizes:
            if size not in IMAGE_SIZES:
                raise ValueError("Received unknown size: %s" % size)

            try:
                sized[size] = image.get_by_size(size)
            except Thumbnail.DoesNotExist:
                pass
            else:
                sizes_to_create.remove(size)

        if sizes_to_create:
            bufs = [
                utils.write_image_in_memory(img)
                for img in utils.scale_and_crop_iter(
                    image.image,
                    [IMAGE_SIZES[size] for size in sizes_to_create])
            ]
            for size, buf in zip(sizes_to_create, bufs):
                # and save to storage
                original_dir, original_file = os.path.split(image.image.name)
                thumb_file = InMemoryUploadedFile(buf, "image", original_file,
                                                  None, buf.tell(), None)
                sized[size], created = image.thumbnail_set.get_or_create(
                    size=size, defaults={'image': thumb_file})

        # Make sure this is in the correct order
        return [sized[size] for size in sizes]

def get_attributes(
        cls, attributes_data: list[AttributeBulkUpdateInput]
    ) -> list[models.Attribute]:
        external_refs: set[str] = set()
        attribute_ids: set[str] = set()

        for attribute_input in attributes_data:
            external_ref = attribute_input.external_reference
            attribute_id = attribute_input.id

            if not external_ref and not attribute_id:
                continue

            if attribute_id:
                attribute_ids.add(graphene.Node.from_global_id(attribute_id)[1])
            else:
                external_refs.add(external_ref)

        if attribute_ids and external_refs:
            lookup = Q(pk__in=attribute_ids) | Q(external_reference__in=external_refs)
        elif attribute_ids:
            lookup = Q(pk__in=attribute_ids)
        elif external_refs:
            lookup = Q(external_reference__in=external_refs)
        else:
            return []

        attributes = list(models.Attribute.objects.filter(lookup))
        attributes_with_choices = [
            attr
            for attr in attributes
            if attr.input_type in AttributeInputType.TYPES_WITH_CHOICES
        ]
        prefetch_related_objects(attributes_with_choices, "values")
        return list(attributes)

